import{c as a,Q as t,j as s,m as i}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Analysis Families","description":"","frontmatter":{},"headers":[],"relativePath":"analysis.md","filePath":"analysis.md","lastUpdated":1779998571000}'),o={name:"analysis.md"};function d(r,e,n,l,c,p){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="analysis-families" tabindex="-1">Analysis Families <a class="header-anchor" href="#analysis-families" aria-label="Permalink to &quot;Analysis Families&quot;">​</a></h1><p>This page documents the analysis outputs used by the main app. Use it to decide which analysis job to run before spending CPU or GPU time. For the separate classifier labeling and training tool, see <a href="./rhythm-lab.html">Rhythm Lab</a>.</p><h2 id="analysis-families-1" tabindex="-1">Analysis Families <a class="header-anchor" href="#analysis-families-1" aria-label="Permalink to &quot;Analysis Families&quot;">​</a></h2><p>Each family writes different SQLite data and supports a different workflow:</p><table tabindex="0"><thead><tr><th>Family</th><th>What it does</th><th>Use when</th></tr></thead><tbody><tr><td>Sonara</td><td>Extracts explainable playlist features such as tempo, energy, loudness, rhythm, and tonal summaries.</td><td>You want fast seed search, visible feature controls, or library filters.</td></tr><tr><td>MAEST</td><td>Predicts genre labels and stores MAEST embeddings.</td><td>You want generated genre tags, genre review, the <code>syncopated</code> preset, or classifier inputs.</td></tr><tr><td>MERT</td><td>Builds audio embeddings for seed-track similarity.</td><td>You want &quot;find tracks close to this track&quot; behavior from an audio model.</td></tr><tr><td>CLAP</td><td>Builds music audio embeddings and text vectors.</td><td>You want text-to-audio search from descriptive prompts.</td></tr><tr><td>Promoted classifiers</td><td>Scores tracks with a local model trained in Rhythm Lab.</td><td>You want a reusable custom signal such as vocal presence, live instrumentation, or another profile-specific label.</td></tr></tbody></table><h3 id="sonara" tabindex="-1">Sonara <a class="header-anchor" href="#sonara" aria-label="Permalink to &quot;Sonara&quot;">​</a></h3><p>Sonara is used in playlist mode as a fast explainable feature pass. It stores focused playlist features under <code>metadata_json.sonara_features</code> and the model name under <code>metadata_json.sonara_model</code>.</p><p>Stored groups and keys:</p><ul><li>Core features: <code>bpm</code>, <code>beats</code>, <code>onset_frames</code>, <code>onset_density</code>, <code>n_beats</code>, <code>rms_mean</code>, <code>rms_max</code>, <code>loudness_lufs</code>, <code>dynamic_range_db</code>, <code>spectral_centroid_mean</code>, <code>zero_crossing_rate</code>, <code>duration_sec</code>.</li><li>Perceptual features: <code>energy</code>, <code>danceability</code>, <code>valence</code>, <code>acousticness</code>.</li><li>Musical key: <code>key</code>, <code>key_confidence</code>.</li><li>Tonal analysis: <code>predominant_chord</code>, <code>chord_change_rate</code>, <code>dissonance</code>.</li><li>Spectral features: <code>spectral_bandwidth_mean</code>, <code>spectral_rolloff_mean</code>, <code>spectral_flatness_mean</code>, <code>spectral_contrast_mean</code>, <code>mfcc_mean</code>, <code>chroma_mean</code>.</li></ul><p>Sonara BPM and key are analyzed values, not copied from file tags. The app keeps raw Sonara key data and does not derive Camelot notation.</p><p>The CLI and UI call Sonara with <code>batch_size</code> as parallel track workers, not as a neural-network inference batch.</p><p>Run Sonara early if you are unsure where to start. It is the most transparent analysis family because the UI can show and mix its feature groups directly.</p><h3 id="maest" tabindex="-1">MAEST <a class="header-anchor" href="#maest" aria-label="Permalink to &quot;MAEST&quot;">​</a></h3><p>MAEST writes genre metadata and embeddings only to SQLite during analysis:</p><ul><li><code>metadata_json.maest_model</code></li><li><code>metadata_json.maest_genres</code></li><li><code>metadata_json.maest_syncopated_rhythm</code></li><li><code>embeddings.embedding_key = &quot;maest&quot;</code></li></ul><p>The adapter uses <code>maest-infer</code> with <code>discogs-maest-30s-pw-129e-519l</code>. It analyzes up to three 30-second windows per track:</p><ul><li>the 60-second offset;</li><li>a window near 38 percent of duration;</li><li>a window near 72 percent of duration.</li></ul><p>Impossible or duplicate windows are clamped and deduplicated. Per-label activations are averaged across windows, then the top labels are stored. MAEST embedding rows are averaged across the same windows and stored under embedding key <code>maest</code>.</p><p>MAEST analysis itself does not modify audio files. The separate genre-save action can later write stored MAEST labels into standard audio genre tags. The <code>maest_syncopated_rhythm</code> flag is derived from saved MAEST genres and is used by the library <code>syncopated</code> preset.</p><p>Run MAEST before using genre writing or the <code>syncopated</code> preset. Review labels before writing them to files; analysis is database-only, but tag writing is an explicit audio-file mutation.</p><h3 id="mert" tabindex="-1">MERT <a class="header-anchor" href="#mert" aria-label="Permalink to &quot;MERT&quot;">​</a></h3><p>MERT builds audio-to-audio embeddings under embedding key <code>mert</code>.</p><p>The default model is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>m-a-p/MERT-v1-95M</span></span></code></pre></div><p>MERT search uses only MERT vectors. It does not mix with Sonara features or CLAP vectors.</p><p>Run MERT when seed-track similarity matters more than explainable controls. Search results depend on existing MERT embeddings, so newly scanned tracks must be analyzed before they appear in useful MERT results.</p><h3 id="clap" tabindex="-1">CLAP <a class="header-anchor" href="#clap" aria-label="Permalink to &quot;CLAP&quot;">​</a></h3><p>CLAP builds music-focused audio embeddings under embedding key <code>clap</code> and creates text vectors for text-to-audio search.</p><p>The active checkpoint is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lukewys/laion_clap/music_audioset_epoch_15_esc_90.14.pt</span></span></code></pre></div><p>Text search requires CLAP audio embeddings produced by the same CLAP checkpoint.</p><p>Run CLAP when you want to search by mood, instrumentation, energy, or other descriptive language. Clear concrete prompts usually work better than single genre words.</p><h3 id="promoted-classifiers" tabindex="-1">Promoted Classifiers <a class="header-anchor" href="#promoted-classifiers" aria-label="Permalink to &quot;Promoted Classifiers&quot;">​</a></h3><p>Promoted classifiers are local classifier profiles, not audio-analysis models that decode files themselves. They score tracks from already stored analysis outputs:</p><ul><li>SONARA playlist features from <code>metadata_json.sonara_features</code>;</li><li>MERT embeddings from <code>embeddings.embedding_key = &quot;mert&quot;</code>;</li><li>MAEST embeddings from <code>embeddings.embedding_key = &quot;maest&quot;</code>.</li></ul><p>Tracks missing any of those inputs are skipped by the classifier job. Scores are stored in <code>track_classifier_scores</code> under the profile classifier key.</p><p>Use promoted classifiers after you have trained and promoted a profile in Rhythm Lab. They are best for personal library concepts that are difficult to capture with a generic genre label or one similarity seed.</p><p>Stable model locations use the profile artifact prefix:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>models/classifiers/&lt;artifact-prefix&gt;/model.joblib</span></span></code></pre></div><p>Those files are produced outside the main app by Rhythm Lab&#39;s promotion command:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tools\\rhythm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lab\\rhythm_lab_cli.py promote </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">profile live_instrumentation</span></span></code></pre></div><p>The promoted <code>model.joblib</code> and <code>model.json</code> files are local artifacts and are ignored by git. The source Rhythm Lab training artifacts remain in the classifier-specific lab workspace:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tools/rhythm-lab/artifacts/&lt;artifact-prefix&gt;/</span></span></code></pre></div><p>Promoted metadata is generated from the Rhythm Lab profile and model artifact: <code>classifier_key</code>, profile name, profile type, labels, feature set, source artifact, and training label counts. Rhythm Lab training metrics use the same profile-neutral shape for all profiles (<code>positive_*</code> metrics and <code>label_order</code>) instead of classifier-specific metric aliases.</p><p>For Rhythm Lab profile management, labeling, training, prediction, promotion, archive, and delete workflows, see <a href="./rhythm-lab.html">Rhythm Lab</a>.</p><p>The user-facing score is the classifier probability for the profile&#39;s positive training label. Because UI displays can round probabilities, a value shown as <code>1.0000</code> may be slightly below mathematical <code>1.0</code>. Use thresholds such as <code>0.99</code>, <code>0.95</code>, or <code>0.90</code> for practical filtering instead of relying on exact <code>1.0</code>.</p>',46)])])}const u=a(o,[["render",d]]);export{m as __pageData,u as default};
